diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index b821da03c16e..be77df5b016f 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -2965,6 +2965,53 @@ void InnerLoopVectorizer::fixVectorizedLoop(VPTransformState &State,
                    getOrCreateVectorTripCount(VectorLoop->getLoopPreheader()),
                    IVEndValues[Entry.first], LoopMiddleBlock,
                    VectorLoop->getHeader(), Plan, State);
+  
+      // Some exit phis may not be modeled in VPlan and thus are not fixed by
+      // VPLiveOuts. Ensure structural correctness by adding an incoming edge
+      // for the newly inserted predecessor to any remaining phis in the exit
+      // blocks that do not yet have one.
+      SmallVector<BasicBlock *> ExitBlocksFix;
+      OrigLoop->getExitBlocks(ExitBlocksFix);
+      for (BasicBlock *ExitBB : ExitBlocksFix) {
+        // Skip if there is no new predecessor from the vectorized loop's middle block.
+        // Only fix phis when LoopMiddleBlock actually reaches ExitBB.
+        bool HasMiddlePred = false;
+        for (auto *Pred : predecessors(ExitBB)) {
+          if (Pred == LoopMiddleBlock) {
+            HasMiddlePred = true;
+            break;
+          }
+        }
+        if (!HasMiddlePred)
+          continue;
+        for (PHINode &PN : ExitBB->phis()) {
+          bool HasIncomingFromMiddle = false;
+          for (unsigned i = 0, e = PN.getNumIncomingValues(); i != e; ++i) {
+            if (PN.getIncomingBlock(i) == LoopMiddleBlock) {
+              HasIncomingFromMiddle = true;
+              break;
+            }
+          }
+          if (!HasIncomingFromMiddle) {
+            {
+            // Try to reuse a loop-invariant incoming value if available.
+            Value *InvariantIncoming = nullptr;
+            for (unsigned j = 0, je = PN.getNumIncomingValues(); j != je; ++j) {
+              Value *IncV = PN.getIncomingValue(j);
+              if (OrigLoop->isLoopInvariant(IncV)) {
+                InvariantIncoming = IncV;
+                break;
+              }
+            }
+            if (!InvariantIncoming)
+              InvariantIncoming = UndefValue::get(PN.getType());
+            PN.addIncoming(InvariantIncoming, LoopMiddleBlock);
+          }
+          }
+        }
+      }
+
+
   }

   // Fix live-out phis not already fixed earlier.

